 1	import React, { FC, useEffect, useState } from 'react';
 2	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 7	import { createURL } from '@virtualmachines/details/tabs/overview/utils/utils';
 8	
 9	import CheckupsNetworkList from './network/list/CheckupsNetworkList';
10	import CheckupsStorageList from './storage/list/CheckupsStorageList';
11	import { trimLastHistoryPath } from './utils/utils';
12	import CheckupsRunButton from './CheckupsRunButton';
13	
14	import './checkups.scss';
15	
16	const CheckupsList: FC = () => {
17	  const { t } = useKubevirtTranslation();
18	  const navigate = useNavigate();
19	  const location = useLocation();
20	  const [activeTabKey, setActiveTabKey] = useState<number | string>(
21	    location?.pathname.endsWith('storage') ? 1 : 0,
22	  );
23	
24	  useEffect(() => {
25	    navigate(
26	      createURL(activeTabKey === 0 ? 'network' : 'storage', trimLastHistoryPath(location.pathname)),
27	    );
28	  }, [activeTabKey, location.pathname, navigate]);
29	
30	  return (
31	    <>
32	      <ListPageHeader title={t('Checkups')}>
33	        <CheckupsRunButton />
34	      </ListPageHeader>
35	      <Tabs
36	        onSelect={(_, tabIndex: number | string) => {
37	          setActiveTabKey(tabIndex);
38	        }}
39	        activeKey={activeTabKey}
40	      >
41	        <Tab eventKey={0} title={<TabTitleText>{t('Network latency')}</TabTitleText>}>
42	          <CheckupsNetworkList />
43	        </Tab>
44	        <Tab eventKey={1} title={<TabTitleText>{t('Storage')}</TabTitleText>}>
45	          <CheckupsStorageList />
46	        </Tab>
47	      </Tabs>
48	    </>
49	  );
50	};
51	
52	export default CheckupsList;

